type Props = {
  className?: ClassValue;
  images: string[];
  illustration: CapsuleIllustration;
  message?: Maybe<string>;
};

export default function Capsule({ images, illustration, message, className }: Props) {
  function render() {
    switch (images.length) {
      case 1:
        return <Single className={className} illustration={illustration} image={images[0]} message={message} />;
      case 2:
        return <Double className={className} illustration={illustration} images={images} message={message} />;
      default:
        return <Triple className={className} illustration={illustration} images={images} message={message} />;
    }
  }

  return render();
}
